class TestCryptoDeepOversold(unittest.TestCase):
    def test_fires_on_deep_oversold_both(self):
        stats = {'consecutive_losses': 0}
        fired, reason = heuristic_crypto_deep_oversold(stats, 26.7, 34.2)
        self.assertTrue(fired)
        self.assertIn('26.7', reason)

    def test_no_fire_btc_not_oversold(self):
        stats = {'consecutive_losses': 0}
        fired, _ = heuristic_crypto_deep_oversold(stats, 26.7, 40.0)
        self.assertFalse(fired)

    def test_no_fire_eth_not_oversold(self):
        stats = {'consecutive_losses': 0}
        fired, _ = heuristic_crypto_deep_oversold(stats, 30.0, 34.2)
        self.assertFalse(fired)

    def test_no_fire_on_consecutive_losses(self):
        stats = {'consecutive_losses': 1}
        fired, _ = heuristic_crypto_deep_oversold(stats, 26.7, 34.2)
        self.assertFalse(fired)

    def test_boundary_eth_exactly_28(self):
        stats = {'consecutive_losses': 0}
        fired, _ = heuristic_crypto_deep_oversold(stats, 28.0, 34.2)
        self.assertFalse(fired)

    def test_boundary_btc_exactly_36(self):
        stats = {'consecutive_losses': 0}
        fired, _ = heuristic_crypto_deep_oversold(stats, 26.7, 36.0)
        self.assertFalse(fired)
